const I18n = (function () {
'use strict';
  const { en, ar } = I18nData;
const STORAGE_KEY = 'agroberry:lang';
const SUPPORTED = ['en', 'ar'];
const RTL_LANGS = new Set(['ar']);
const LOCALES = { en, ar };

let currentLang = 'en';
let dict = en;

function getByPath(obj, path) {
  return path.split('.').reduce((acc, key) => (acc && acc[key] !== undefined ? acc[key] : undefined), obj);
}

function t(key, fallback = '') {
  const value = getByPath(dict, key);
  return value !== undefined ? value : fallback;
}

function getLang() {
  return currentLang;
}

function isRTL() {
  return RTL_LANGS.has(currentLang);
}

function applyTranslations() {
  document.documentElement.lang = currentLang;
  document.documentElement.dir = isRTL() ? 'rtl' : 'ltr';

  document.querySelectorAll('[data-i18n]').forEach((el) => {
    const key = el.getAttribute('data-i18n');
    const value = getByPath(dict, key);
    if (value !== undefined) el.textContent = value;
  });

  document.querySelectorAll('[data-i18n-placeholder]').forEach((el) => {
    const key = el.getAttribute('data-i18n-placeholder');
    const value = getByPath(dict, key);
    if (value !== undefined) el.setAttribute('placeholder', value);
  });

  document.title = getByPath(dict, 'meta.title') || document.title;
  const setMeta = (selector, attr, key) => {
    const el = document.querySelector(selector);
    const value = getByPath(dict, key);
    if (el && value !== undefined) el.setAttribute(attr, value);
  };
  setMeta('meta[name="description"]', 'content', 'meta.description');
  setMeta('meta[property="og:title"]', 'content', 'meta.ogTitle');
  setMeta('meta[property="og:description"]', 'content', 'meta.ogDescription');
  setMeta('meta[name="twitter:title"]', 'content', 'meta.ogTitle');
  setMeta('meta[name="twitter:description"]', 'content', 'meta.ogDescription');

  document.querySelectorAll('[data-lang]').forEach((el) => {
    el.classList.toggle('is-active', el.getAttribute('data-lang') === currentLang);
  });

  document.dispatchEvent(new CustomEvent('i18n:ready', { detail: { lang: currentLang, dict } }));
}

function setLang(lang) {
  if (!SUPPORTED.includes(lang)) lang = 'en';
  dict = LOCALES[lang] || en;
  currentLang = lang;
  try {
    localStorage.setItem(STORAGE_KEY, lang);
  } catch (err) {
    // localStorage unavailable (e.g. file:// in some browsers) — safe to ignore
  }
  applyTranslations();
}

function initI18n() {
  let saved = null;
  try {
    saved = localStorage.getItem(STORAGE_KEY);
  } catch (err) {
    // ignore
  }
  const initial = SUPPORTED.includes(saved) ? saved : 'en';
  setLang(initial);

  const langSwitch = document.getElementById('langSwitch');
  if (langSwitch) {
    langSwitch.addEventListener('click', () => {
      const next = currentLang === 'en' ? 'ar' : 'en';
      setLang(next);
    });
  }
}
return { t, getLang, isRTL, setLang, initI18n };
})();

const Reveal = (function () {
'use strict';
const prefersReduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

let revealObserver = null;

function getRevealObserver() {
  if (revealObserver || prefersReduced) return revealObserver;
  revealObserver = new IntersectionObserver(
    (entries, obs) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          entry.target.classList.add('is-visible');
          obs.unobserve(entry.target);
        }
      });
    },
    { threshold: 0.15, rootMargin: '0px 0px -40px 0px' }
  );
  return revealObserver;
}

function observeReveal(scope = document) {
  const els = scope.querySelectorAll('.reveal:not(.is-visible), .reveal-scale:not(.is-visible)');
  if (!els.length) return;
  if (prefersReduced) {
    els.forEach((el) => el.classList.add('is-visible'));
    return;
  }
  const observer = getRevealObserver();
  els.forEach((el) => observer.observe(el));
}

function initReveal() {
  observeReveal(document);
}

function initCounters() {
  const counters = document.querySelectorAll('.counter');
  if (!counters.length) return;

  const animateCounter = (el) => {
    const target = parseInt(el.getAttribute('data-count'), 10) || 0;
    if (prefersReduced) {
      el.textContent = target.toLocaleString();
      return;
    }
    const duration = 1600;
    const start = performance.now();
    const ease = (x) => 1 - Math.pow(1 - x, 3);

    function tick(now) {
      const elapsed = now - start;
      const progress = Math.min(elapsed / duration, 1);
      const value = Math.round(ease(progress) * target);
      el.textContent = value.toLocaleString();
      if (progress < 1) requestAnimationFrame(tick);
    }
    requestAnimationFrame(tick);
  };

  const observer = new IntersectionObserver(
    (entries, obs) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          animateCounter(entry.target);
          obs.unobserve(entry.target);
        }
      });
    },
    { threshold: 0.5 }
  );

  counters.forEach((el) => observer.observe(el));
}
return { observeReveal, initReveal, initCounters };
})();

const Lightbox = (function () {
'use strict';
let state = {
  items: [],
  index: 0,
};

let lightbox, content, closeBtn, prevBtn, nextBtn;

function renderCurrent() {
  const item = state.items[state.index];
  if (!item) return;
  content.innerHTML = '';

  if (item.type === 'video') {
    const video = document.createElement('video');
    video.src = item.src;
    video.controls = true;
    video.autoplay = true;
    video.playsInline = true;
    if (item.poster) video.poster = item.poster;
    content.appendChild(video);
  } else {
    const img = document.createElement('img');
    img.src = item.src;
    img.alt = item.caption || '';
    content.appendChild(img);
  }

  if (item.caption) {
    const cap = document.createElement('p');
    cap.className = 'lightbox-caption';
    cap.textContent = item.caption;
    content.appendChild(cap);
  }

  const multi = state.items.length > 1;
  prevBtn.style.display = multi ? '' : 'none';
  nextBtn.style.display = multi ? '' : 'none';
}

function stopMedia() {
  content.querySelectorAll('video').forEach((v) => v.pause());
}

function closeLightbox() {
  stopMedia();
  lightbox.classList.remove('is-open');
  document.body.style.overflow = '';
}

function openLightbox(items, startIndex = 0) {
  state.items = items;
  state.index = startIndex;
  lightbox.classList.add('is-open');
  document.body.style.overflow = 'hidden';
  renderCurrent();
}

function next() {
  stopMedia();
  state.index = (state.index + 1) % state.items.length;
  renderCurrent();
}

function prev() {
  stopMedia();
  state.index = (state.index - 1 + state.items.length) % state.items.length;
  renderCurrent();
}

function initLightbox() {
  lightbox = document.getElementById('lightbox');
  content = document.getElementById('lightboxContent');
  closeBtn = document.getElementById('lightboxClose');
  prevBtn = document.getElementById('lightboxPrev');
  nextBtn = document.getElementById('lightboxNext');
  if (!lightbox) return;

  closeBtn.addEventListener('click', closeLightbox);
  nextBtn.addEventListener('click', next);
  prevBtn.addEventListener('click', prev);

  lightbox.addEventListener('click', (e) => {
    if (e.target === lightbox) closeLightbox();
  });

  window.addEventListener('keydown', (e) => {
    if (!lightbox.classList.contains('is-open')) return;
    if (e.key === 'Escape') closeLightbox();
    if (e.key === 'ArrowRight') next();
    if (e.key === 'ArrowLeft') prev();
  });
}
return { closeLightbox, openLightbox, initLightbox };
})();

const Nav = (function () {
'use strict';
function initNav() {
  const header = document.getElementById('siteHeader');
  const nav = document.getElementById('mainNav');
  const toggle = document.getElementById('navToggle');
  const close = document.getElementById('navClose');
  const backToTop = document.getElementById('backToTop');
  const navLinks = nav ? Array.from(nav.querySelectorAll('a[href^="#"]')) : [];

  const onScroll = () => {
    const scrolled = window.scrollY > 40;
    header?.classList.toggle('is-scrolled', scrolled);
    backToTop?.classList.toggle('is-visible', window.scrollY > 700);
  };
  onScroll();
  window.addEventListener('scroll', onScroll, { passive: true });

  const openNav = () => {
    nav?.classList.add('is-open');
    toggle?.setAttribute('aria-expanded', 'true');
    document.body.style.overflow = 'hidden';
    document.body.classList.add('nav-open');
  };
  const closeNav = () => {
    nav?.classList.remove('is-open');
    toggle?.setAttribute('aria-expanded', 'false');
    document.body.style.overflow = '';
    document.body.classList.remove('nav-open');
  };

  toggle?.addEventListener('click', openNav);
  close?.addEventListener('click', closeNav);
  navLinks.forEach((link) => link.addEventListener('click', closeNav));

  window.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') closeNav();
  });

  backToTop?.addEventListener('click', () => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  });

  if (navLinks.length) {
    const sections = navLinks
      .map((link) => document.querySelector(link.getAttribute('href')))
      .filter(Boolean);

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (!entry.isIntersecting) return;
          const id = `#${entry.target.id}`;
          navLinks.forEach((link) => {
            link.classList.toggle('is-active', link.getAttribute('href') === id);
          });
        });
      },
      { rootMargin: '-45% 0px -50% 0px', threshold: 0 }
    );

    sections.forEach((section) => observer.observe(section));
  }
}
return { initNav };
})();

const Hero = (function () {
'use strict';
function initHero() {
  const video = document.getElementById('heroVideo');
  const poster = document.getElementById('heroPoster');
  if (!video) return;

  const prefersReduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

  if (prefersReduced) {
    video.removeAttribute('autoplay');
    video.pause();
    return; // keep the static poster only
  }

  const reveal = () => {
    video.classList.add('is-ready');
    poster?.classList.remove('is-ready');
  };

  if (video.readyState >= 2) {
    reveal();
  } else {
    video.addEventListener('loadeddata', reveal, { once: true });
  }

  const tryPlay = () => video.play().catch(() => {});
  tryPlay();
  document.addEventListener('click', tryPlay, { once: true });
}
return { initHero };
})();

